import { UnitType } from "./mapTypes";

//拖拽数据
export interface DragType {
  //被拖拽节点的父节点
  parent: cc.Node;
  //被拖拽节点
  itemNode: cc.Node;
  //鼠标位置
  mousePos: cc.Vec2;
  //鼠标与anchor的偏移
  dragOffset: cc.Vec3;
  /** 拖拽过程中鼠标命中的房间（可选；由 LevelScene 实时写入） */
  hoverRoomId?: number;
  hoverRoomName?: string;
  /** 拖拽过程中鼠标命中的 layer 容器（仅拖拽房间时使用） */
  hoverLayerNode?: cc.Node;
  hoverLayerName?: string;
}

//鼠标移动到节点
export interface HoverType {
  //节点名称
  name: string;
  //世界坐标
  worldPos: cc.Vec2;
  width: number;
  height: number;
}

//属性面板
export interface attrPanelType {
  type: UnitType;
  dat:
  | attrPanelTypeBase
  | attrPanelTypeRoom
  | attrPanelTypePoint
  | attrPanelTypeDoor
  | attrPanelTypeLadder
  | attrPanelTypeSurvive
  | attrPanelTypeSearchItem
  | attrPanelTypePortal
  | attrPanelTypeCable
  | attrPanelTypeEnemyRefresh
  | attrPanelTypeSurviveRefresh
}

export interface attrPanelTypeBase {
  name: string;
  pos: cc.Vec2;
}

export interface attrPanelTypeRoom {
  roomId: string;
  size: { width: number; height: number };
  unLockPoints: cc.Node[];
}

export interface attrPanelTypePoint {
  roomId: string;
  links: cc.Node[];
}

export interface attrPanelTypeDoor {
  roomId: string;
  hp: number;
}

export interface attrPanelTypeEnemyRefresh {
  roomId: string;
  param: string;
  refreshId: number;
}

export interface attrPanelTypeSurviveRefresh {
  roomId: string;
  weight: number;
}

export interface attrPanelTypeLadder {
  roomId: string;
  bindPointIds: cc.Node[];
  isExitLadder: boolean;
}

export interface attrPanelTypeSurvive {
  roomId: string;
  weight: number;
}

export interface attrPanelTypeSearchItem {
  roomId: string;
  param: string;
}

export interface attrPanelTypePortal {
  linkP: cc.Node;
  offsetX: number;
  animPs: cc.Node[];
}

export interface attrPanelTypeCable {
  startP: cc.Node;
  endP: cc.Node;
  points: cc.Node[];
  speed: number;
}

export enum ModeType {
  PathPointLink = "PathPointLink",
  LadderBind = "LadderBind",
  SelectPoint = "SelectPoint",
}